\begin{align}
\lim_{x\to 90} \frac{\sin x}{\cos x} &= \lim_{x\to 90} \frac{\sin x}{\sqrt{1-(\sin x)^2}}
\subfloat[]{\begin{align*} & \quad\ \, (\cos x)^2 = 1-(\sin x)^2\\ & \qquad \color{red}{\sin^2 x + \cos^2 x = 1} \end{align*}} 
\\
&= \lim_{x\to 90} \frac{\frac{\sin x}{\cos x}}{\sqrt{1-\frac{1}{\cos^2 x}}}
\\
&= \lim_{x\to 90} \frac{\sec x}{\sqrt{\sec^2 x - 1}}
\\
&= \lim_{x\to 90} \frac{1}{\sqrt{\tan^2 x }} \tag*{(using $\sec^2 x = 1+\tan^2 x$)}\\
&= \lim_{x\to 90} \frac{1}{\tan x} \tag*{(using $\tan^2 x = \sec^2 x - 1$)}
\end{align}
This is equal to $1/0$. In other words, a number that is undefined!
